    private static ToIntFunction<BlockState> litBlockEmission(int lightEmission) {
        return state -> state.getValue(BlockStateProperties.LIT) != false ? lightEmission : 0;
    }

    private static Function<BlockState, MapColor> waterloggedMapColor(MapColor mapColor) {
        return blockState -> blockState.getValue(BlockStateProperties.WATERLOGGED) != false ? MapColor.WATER : mapColor;
    }

    private static Boolean never(BlockState state, BlockGetter blockGetter, BlockPos blockPos, EntityType<?> entityType) {
        return false;
    }

    private static Boolean always(BlockState state, BlockGetter blockGetter, BlockPos blockPos, EntityType<?> entityType) {
        return true;
    }

    private static Boolean ocelotOrParrot(BlockState state, BlockGetter blockGetter, BlockPos blockPos, EntityType<?> entityType) {
        return entityType == EntityType.OCELOT || entityType == EntityType.PARROT;
    }

    private static Block registerBed(String id, DyeColor color) {
        return Blocks.register(id, (BlockBehaviour.Properties p) -> new BedBlock(color, (BlockBehaviour.Properties)p), BlockBehaviour.Properties.of().mapColor(state -> state.getValue(BedBlock.PART) == BedPart.FOOT ? color.getMapColor() : MapColor.WOOL).sound(SoundType.WOOD).strength(0.2f).noOcclusion().ignitedByLava().pushReaction(PushReaction.DESTROY));
    }

    private static BlockBehaviour.Properties logProperties(MapColor topColor, MapColor sideColor, SoundType soundType) {
        return BlockBehaviour.Properties.of().mapColor(state -> state.getValue(RotatedPillarBlock.AXIS) == Direction.Axis.Y ? topColor : sideColor).instrument(NoteBlockInstrument.BASS).strength(2.0f).sound(soundType).ignitedByLava();
    }

    private static BlockBehaviour.Properties netherStemProperties(MapColor mapColor) {
        return BlockBehaviour.Properties.of().mapColor(state -> mapColor).instrument(NoteBlockInstrument.BASS).strength(2.0f).sound(SoundType.STEM);
    }

    private static boolean always(BlockState state, BlockGetter blockGetter, BlockPos blockPos) {
        return true;
    }

    private static boolean never(BlockState state, BlockGetter blockGetter, BlockPos blockPos) {
        return false;
    }

    private static Block registerStainedGlass(String id, DyeColor color) {
        return Blocks.register(id, (BlockBehaviour.Properties p) -> new StainedGlassBlock(color, (BlockBehaviour.Properties)p), BlockBehaviour.Properties.of().mapColor(color).instrument(NoteBlockInstrument.HAT).strength(0.3f).sound(SoundType.GLASS).noOcclusion().isValidSpawn(Blocks::never).isRedstoneConductor(Blocks::never).isSuffocating(Blocks::never).isViewBlocking(Blocks::never));
    }

